import {
  type CSSProperties,
  forwardRef,
  type HTMLAttributes,
  type KeyboardEvent,
  type ReactNode,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { type ComponentSize, useDisabled, useSize } from '../../config-provider';
import { Icon, LoadingIcon } from '../Icon';

export interface SwitchProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'onChange' | 'defaultValue'> {
  /** Controlled checked state. */
  value?: boolean;
  /** Initial checked state for the uncontrolled mode. */
  defaultValue?: boolean;
  /** Fired with the next checked state. */
  onChange?: (value: boolean) => void;
  /** Disable the control. */
  disabled?: boolean;
  /** Show a loading spinner and block interaction. */
  loading?: boolean;
  /** Size. Falls back to the nearest ConfigProvider. */
  size?: ComponentSize;
  /** Text shown when on. */
  activeText?: string;
  /** Text shown when off. */
  inactiveText?: string;
  /** Render the texts inside the rail instead of beside it. */
  inlinePrompt?: boolean;
  /** Custom rail width. */
  width?: number | string;
  /** Icon shown on the knob when on. */
  activeIcon?: ReactNode;
  /** Icon shown on the knob when off. */
  inactiveIcon?: ReactNode;
  /** Native `name` attribute, mirrored onto a hidden input. */
  name?: string;
  /** Native `id` attribute. */
  id?: string;
  /** Accessible name for the `switch` role. */
  'aria-label'?: string;
  /** ID of the element labelling the `switch` role. */
  'aria-labelledby'?: string;
  /** Extra class on the root element. */
  className?: string;
  /** Extra style on the root element. */
  style?: CSSProperties;
}

export const Switch = forwardRef<HTMLDivElement, SwitchProps>(function Switch(props, ref) {
  const {
    value,
    defaultValue,
    onChange,
    disabled: disabledProp,
    loading = false,
    size: sizeProp,
    activeText,
    inactiveText,
    inlinePrompt = false,
    width,
    activeIcon,
    inactiveIcon,
    name,
    id,
    className,
    style,
    ...rest
  } = props;

  const ns = useNamespace('switch');
  const size = useSize(sizeProp);
  const disabled = useDisabled(disabledProp) || loading;

  const isControlled = value !== undefined;
  const [inner, setInner] = useState(defaultValue ?? false);
  const checked = isControlled ? value : inner;

  const toggle = () => {
    if (disabled) return;
    const next = !checked;
    if (!isControlled) setInner(next);
    onChange?.(next);
  };

  const handleKeyDown = (event: KeyboardEvent<HTMLDivElement>) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      toggle();
    }
  };

  const classes = cls(
    ns.b(),
    size !== 'default' && ns.m(size),
    ns.is('checked', checked),
    ns.is('disabled', disabled),
    ns.is('loading', loading),
    className,
  );

  const coreStyle: CSSProperties =
    width !== undefined ? { width: typeof width === 'number' ? `${width}px` : width } : {};

  const renderText = (text: string | undefined, active: boolean) =>
    text !== undefined && (
      <span className={cls(ns.e('label'), ns.em('label', active ? 'right' : 'left'), ns.is('active', checked === active))}>
        {text}
      </span>
    );

  return (
    <div
      ref={ref}
      {...rest}
      role="switch"
      tabIndex={disabled ? -1 : 0}
      aria-checked={checked}
      aria-disabled={disabled || undefined}
      id={id}
      className={classes}
      style={style}
      onClick={toggle}
      onKeyDown={handleKeyDown}
    >
      {name !== undefined && <input type="hidden" name={name} value={checked ? 'true' : 'false'} />}
      {!inlinePrompt && renderText(inactiveText, false)}
      <span className={ns.e('core')} style={coreStyle}>
        {inlinePrompt && (
          <span className={ns.e('inner')}>
            {checked
              ? activeText !== undefined && (
                  <span className={cls(ns.e('inner-text'), ns.is('active'))}>{activeText}</span>
                )
              : inactiveText !== undefined && (
                  <span className={ns.e('inner-text')}>{inactiveText}</span>
                )}
          </span>
        )}
        <span className={ns.e('action')}>
          {loading ? (
            <Icon className={ns.e('loading')} spin>
              <LoadingIcon />
            </Icon>
          ) : checked ? (
            activeIcon && <Icon className={ns.e('icon')}>{activeIcon}</Icon>
          ) : (
            inactiveIcon && <Icon className={ns.e('icon')}>{inactiveIcon}</Icon>
          )}
        </span>
      </span>
      {!inlinePrompt && renderText(activeText, true)}
    </div>
  );
});

.ec-switch {
  --ec-switch-on-color: var(--ec-color-primary);
  --ec-switch-off-color: var(--ec-border-color);
  --ec-switch-on-border-color: var(--ec-color-primary);
  --ec-switch-off-border-color: var(--ec-border-color);
  --ec-switch-core-height: 20px;
  --ec-switch-core-min-width: 40px;
  --ec-switch-action-size: 16px;
  --ec-switch-font-size: var(--ec-font-size-base);
  --ec-switch-text-color: var(--ec-text-color-primary);

  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  height: var(--ec-component-size);
  font-size: var(--ec-switch-font-size);
  line-height: var(--ec-switch-core-height);
  vertical-align: middle;
  cursor: pointer;
  outline: none;
}

.ec-switch__label {
  display: inline-flex;
  align-items: center;
  height: 100%;
  font-size: var(--ec-switch-font-size);
  font-weight: var(--ec-font-weight-primary);
  color: var(--ec-switch-text-color);
  transition: var(--ec-transition-color);
  user-select: none;
}

.ec-switch__label--left {
  margin-right: 10px;
}

.ec-switch__label--right {
  margin-left: 10px;
}

.ec-switch__label.is-active {
  color: var(--ec-color-primary);
}

.ec-switch__core {
  position: relative;
  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  width: var(--ec-switch-core-min-width);
  min-width: var(--ec-switch-core-min-width);
  height: var(--ec-switch-core-height);
  background-color: var(--ec-switch-off-color);
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-switch-off-border-color);
  border-radius: calc(var(--ec-switch-core-height) / 2);
  outline: none;
  transition: var(--ec-transition-all);
}

.ec-switch__action {
  position: absolute;
  left: 1px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: var(--ec-switch-action-size);
  height: var(--ec-switch-action-size);
  color: var(--ec-switch-off-color);
  background-color: var(--ec-color-white);
  border-radius: var(--ec-border-radius-circle);
  transition: var(--ec-transition-all);
}

.ec-switch__icon {
  font-size: 12px;
}

.ec-switch__loading {
  font-size: 12px;
  color: var(--ec-switch-off-color);
}

.ec-switch__inner {
  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  height: 100%;
  width: 100%;
  padding: 0 6px 0 22px;
  overflow: hidden;
  white-space: nowrap;
}

.ec-switch__inner-text {
  font-size: 12px;
  line-height: 1;
  color: var(--ec-color-white);
}

/* ---- Checked ---- */
.ec-switch.is-checked .ec-switch__core {
  background-color: var(--ec-switch-on-color);
  border-color: var(--ec-switch-on-border-color);
}

.ec-switch.is-checked .ec-switch__action {
  left: calc(100% - var(--ec-switch-action-size) - 1px);
  color: var(--ec-switch-on-color);
}

.ec-switch.is-checked .ec-switch__loading {
  color: var(--ec-switch-on-color);
}

.ec-switch.is-checked .ec-switch__inner {
  padding: 0 22px 0 6px;
}

/* ---- Disabled ---- */
.ec-switch.is-disabled {
  cursor: not-allowed;
}

.ec-switch.is-disabled .ec-switch__core,
.ec-switch.is-disabled .ec-switch__label {
  opacity: 0.6;
}

/* ---- Loading ---- */
.ec-switch.is-loading {
  cursor: default;
}

/* ---- Focus ---- */
.ec-switch:focus-visible .ec-switch__core {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: 1px;
}

/* ---- Sizes ---- */
.ec-switch--large {
  height: var(--ec-component-size-large);
  --ec-switch-core-height: 24px;
  --ec-switch-core-min-width: 50px;
  --ec-switch-action-size: 20px;
  --ec-switch-font-size: var(--ec-font-size-medium);
}

.ec-switch--small {
  height: var(--ec-component-size-small);
  --ec-switch-core-height: 16px;
  --ec-switch-core-min-width: 30px;
  --ec-switch-action-size: 12px;
  --ec-switch-font-size: var(--ec-font-size-small);
}
